// @n8n-harness:primitive — exempt from pure-function discipline
const crypto = require('crypto');
return { json: { lock_id: crypto.randomUUID() } };

// @n8n-harness:primitive — exempt from pure-function discipline
// Parse the GET result and decide whether the lock is currently held.
// A lock is "held" iff: the key exists, the value parses as JSON, AND the lock has not expired (locked_at + ttl_seconds > now).
// Stale locks (older than their stored ttl_seconds) are treated as released so a new caller can overwrite.
const raw = $json.SCOPE_LOCK;
let hasActiveLock = false;
let parsed = null;
if (raw !== null && raw !== undefined && raw !== '') {
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    // Legacy non-JSON value — treat as held with unknown ttl (don't auto-expire)
    parsed = { lock_id: String(raw), workflow_id: 'unknown', workflow_name: 'unknown (legacy)', execution_id: 'unknown', locked_at: null, ttl_seconds: null };
  }
  if (parsed && typeof parsed === 'object') {
    const lockedAtMs = parsed.locked_at ? new Date(parsed.locked_at).getTime() : null;
    const ttlSeconds = typeof parsed.ttl_seconds === 'number' ? parsed.ttl_seconds : null;
    if (lockedAtMs && ttlSeconds) {
      hasActiveLock = (Date.now() - lockedAtMs) <= (ttlSeconds * 1000);
    } else {
      // Legacy / no-TTL value — treat as held (conservative: don't auto-overwrite)
      hasActiveLock = true;
    }
  }
}
return [{ json: { has_active_lock: hasActiveLock, parsed_lock: parsed, raw_value: raw } }];
